#include <iostream>
#include <string>
#include <utility>

template <typename T>
T getLarger(T val1, T val2) {
    if (val1 > val2) {
        return val1;
    } else {
        return val2;
    }
}

struct MyData {
    int id;
    std::string name;

    MyData(int i, std::string n) : id(i), name(std::move(n)) {}

    // For demonstration, if MyData were comparable:
    friend std::ostream& operator<<(std::ostream& os, const MyData& md) {
        return os << "{id: " << md.id << ", name: " << md.name << "}";
    }
};

int main() {
    int int1 = 10;
    int int2 = 20;
    std::cout << "Comparing " << int1 << " and " << int2 << ": Larger is " << getLarger(int1, int2) << std::endl;

    double double1 = 15.5;
    double double2 = 7.3;
    std::cout << "Comparing " << double1 << " and " << double2 << ": Larger is " << getLarger(double1, double2) << std::endl;

    MyData data1(1, "Apple");
    MyData data2(2, "Banana");
    // The following line is commented out because it causes the semantic error.
    // If operator> were defined for MyData, it would compile and run.
    // std::cout << "Comparing MyData objects: Larger is " << getLarger(data1, data2) << std::endl;

    return 0;
}
